('sv', 'common', 'dementia.stage_4_desc',    'Tidig Demens'),
('sv', 'common', 'dementia.stages_56',       'Stadier 5–6'),
('sv', 'common', 'dementia.stages_56_desc',  'Medelsvår Demens'),
('sv', 'common', 'dementia.stage_7',         'Stadium 7'),
('sv', 'common', 'dementia.stage_7_desc',    'Sen Demens'),
('sv', 'common', 'dementia.seven_stages',    'De Sju Stadierna'),
('sv', 'common', 'dementia.disclaimer_label','Ansvarsfriskrivning:'),
('sv', 'common', 'dementia.disclaimer_body', 'Denna skala är ett kliniskt referensverktyg avsett enbart för informationsändamål. Det ersätter inte professionell medicinsk rådgivning, diagnos eller behandling. Konsultera en kvalificerad vårdgivare för eventuella medicinska frågor.'),

-- ─────────────── FINNISH ───────────────
('fi', 'common', 'dementia.page_title',      'Dementian Viiteasteikko'),
('fi', 'common', 'dementia.signs_symptoms',  'Merkit ja Oireet'),
('fi', 'common', 'dementia.expected_duration','Odotettu Kesto'),
('fi', 'common', 'dementia.not_applicable',  'Ei sovellettavissa'),
('fi', 'common', 'dementia.note_4',          'Tässä vaiheessa henkilö saattaa olla tietoinen vaikeuksistaan, mutta yrittää peittää tai vähätellä niitä. Lääkäri voi havaita ongelmia kliinisessä haastattelussa.'),
('fi', 'common', 'dementia.note_5',          'Henkilö ei enää pysty selviytymään ilman tukea. Hän muistaa tärkeitä henkilökohtaisia tietoja, mutta saattaa olla unohtanut osoitteensa tai puhelinnumeronsa.'),
('fi', 'common', 'dementia.note_6',          'Henkilö on suurelta osin tietämätön viimeaikaisista tapahtumista ja kokemuksista. Hän tarvitsee merkittävää apua kaikissa päivittäisissä toiminnoissa ja saattaa tarvita ympärivuorokautista valvontaa.'),
('fi', 'common', 'dementia.note_7',          'Kaikki kielelliset kyvyt menetetään tämän vaiheen aikana. Peruspyrkomotoriset taidot häviävät ja henkilö on vuodepotilas. Mukavuuteen keskittyvä hoito on ensisijaista.'),
('fi', 'common', 'dementia.about_title',     'Tietoa Globaalista Heikentymisasteikosta (GDS)'),
('fi', 'common', 'dementia.about_p1',        'Globaali Heikentymisasteikko (GDS), jonka kehitti tri Barry Reisberg, antaa hoitajille yleiskatsauksen kognitiivisen toiminnan vaiheista henkilöillä, jotka kärsivät ensisijaisesta rappeutuvasta dementiasta, kuten Alzheimerin taudista.'),
('fi', 'common', 'dementia.about_p2',        'Asteikko määrittelee 7 vaihetta, jotka vaihtelevat ei kognitiivista heikkenemistä erittäin vakavaan kognitiiviseen heikkenemiseen. GDS on merkityksellisin Alzheimerin tautia sairastaville henkilöille, eikä se välttämättä koske muita dementian muotoja.'),
('fi', 'common', 'dementia.stages_13',       'Vaiheet 1–3'),
('fi', 'common', 'dementia.stages_13_desc',  'Ei Dementiaa'),
('fi', 'common', 'dementia.stage_4',         'Vaihe 4'),
('fi', 'common', 'dementia.stage_4_desc',    'Varhainen Dementia'),
('fi', 'common', 'dementia.stages_56',       'Vaiheet 5–6'),
('fi', 'common', 'dementia.stages_56_desc',  'Keskivaikea Dementia'),
('fi', 'common', 'dementia.stage_7',         'Vaihe 7'),
('fi', 'common', 'dementia.stage_7_desc',    'Myöhäinen Dementia'),
('fi', 'common', 'dementia.seven_stages',    'Seitsemän Vaihetta'),
('fi', 'common', 'dementia.disclaimer_label','Vastuuvapauslauseke:'),
('fi', 'common', 'dementia.disclaimer_body', 'Tämä asteikko on kliininen viitetyökalu, joka on tarkoitettu vain tiedotustarkoituksiin. Se ei korvaa ammattimaista lääketieteellistä neuvontaa, diagnoosia tai hoitoa. Ota yhteyttä pätevään terveydenhuollon tarjoajaan kaikissa lääketieteellisissä kysymyksissä.')

